//! Consumer gateway deployment and G2G routing verification.
//!
//! Deploys a consumer Praxis AI gateway into the first consumer-role cluster
//! defined in the environment config.  Two `grid_route` config modes are
//! supported:
//!
//! - **Static mode (default):** Generates candidates from provider site/model declarations in the environment config.
//! - **Overlay mode:** Reads a routing overlay `grid-config.json`. The overlay `local_site` and candidates drive
//!   `grid_route`; the `load_balancer` section is still generated from provider endpoints in the environment config.
//!
//! Provider endpoints are reached via `NodePort` over the kind Docker bridge.
//! Mutual TLS uses certificates generated by `xtask env up` and stored under
//! `tests/env/certs/`.

use std::{
    net::TcpStream,
    path::{Path, PathBuf},
    process::Command,
    time::{Duration, Instant},
};

use crate::env::{
    config::{ClusterDef, ClusterRole, EnvConfig},
    images::GATEWAY_IMAGE,
    kind::kubectl_context,
    kubectl,
    operator_overlay::{self, RoutingOverlay},
    verify::{HttpResponse, PortForwardGuard, Tally, find_free_port, parse_curl_output, safe_truncate, wait_for_port},
};

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

/// Kubernetes namespace for consumer deployments.
const NAMESPACE: &str = "default";

/// Bearer token stored in the API-provider credential Secret for xtask validation.
///
/// This value is written to a Kubernetes Secret by the xtask validation harness
/// and then read back via the Secret-projection flow to build the Praxis consumer
/// config.  It is never logged, and the generated YAML receives the value from
/// the resolved Secret rather than embedding this compile-time constant directly.
///
/// The validation proves the Secret-backed CRD → Praxis-config flow, not
/// production credential management.
pub(crate) const API_PROVIDER_INJECTED_TOKEN: &str = "grid-api-fallback-secret";

/// Gateway HTTP port.
const GATEWAY_HTTP_PORT: u16 = 8080;

/// `NodePort` range minimum for provider gateway exposure.
const NODE_PORT_BASE: u16 = 30080;

/// Network probe timeout.
const PROBE_TIMEOUT: Duration = Duration::from_secs(5);

/// K8s Secret name holding TLS certs for the consumer gateway pod.
const TLS_SECRET_NAME: &str = "praxis-tls";

/// Path inside the consumer pod where TLS certs are mounted.
const CERT_MOUNT_PATH: &str = "/etc/praxis/tls";

/// Host-side cert directory (relative to workspace root).
const HOST_CERTS_DIR: &str = "tests/env/certs";

/// Base directory for mounted credential Secret files inside the consumer pod.
///
/// Each API credential Secret is mounted at `{CREDENTIAL_MOUNT_BASE}/{secret_name}/{key}`.
/// Token bytes never appear in Praxis `ConfigMap`s with this layout — the
/// `grid_credential_inject` filter reads from the mounted file path instead.
const CREDENTIAL_MOUNT_BASE: &str = "/run/secrets/grid-credentials";

// ---------------------------------------------------------------------------
// Network probe
// ---------------------------------------------------------------------------

/// Probe cross-kind network connectivity from the consumer cluster to all
/// provider gateways.
///
/// Outputs a PASS/FAIL/INFO report for each provider's node IP, `NodePort`
/// reachability, and Docker network adjacency.
///
/// # Errors
///
/// Returns an error only for fatal infrastructure failures.
pub(crate) fn probe_network(cfg: &EnvConfig) -> Result<(), Box<dyn std::error::Error>> {
    eprintln!("Probing cross-kind network connectivity...");
    eprintln!();

    let consumer_site = cfg
        .consumer_cluster_name()
        .ok_or("no consumer cluster configured in environment config")?;
    let consumer_ctx = kubectl_context(consumer_site);

    for name in &cfg.clusters.names {
        let Some(def) = cfg.clusters.definitions.get(name) else {
            continue;
        };
        if def.role != ClusterRole::Provider {
            continue;
        }
        probe_provider_reachability(name, def, &consumer_ctx)?;
    }

    Ok(())
}

/// Probe whether a provider cluster's gateway is reachable from the consumer.
#[expect(clippy::too_many_lines, reason = "sequential probe steps with diagnostic output")]
fn probe_provider_reachability(
    provider: &str,
    _def: &ClusterDef,
    consumer_ctx: &str,
) -> Result<(), Box<dyn std::error::Error>> {
    let provider_ctx = kubectl_context(provider);

    let node_ip = get_kind_node_ip(&provider_ctx)?;
    eprintln!("  provider {provider} kind node IP: {node_ip}");

    let node_port = get_nodeport(&provider_ctx, "praxis-provider");
    match node_port {
        Some(port) => {
            eprintln!("  provider {provider} NodePort: {port}");
            let addr = format!("{node_ip}:{port}");
            let reachable = probe_tcp(&addr);
            if reachable {
                eprintln!("  [PASS] {provider} gateway {addr} reachable from host");
            } else {
                eprintln!(
                    "  [INFO] {provider} gateway {addr} not reachable from host \
                     (may still work from inside cluster)"
                );
            }
        },
        None => {
            eprintln!(
                "  [INFO] {provider} gateway has no NodePort; \
                 will use port-forward from consumer"
            );
        },
    }

    let same_network = check_docker_network(&provider_ctx, consumer_ctx)?;
    if same_network {
        eprintln!("  [PASS] provider and consumer kind nodes share a Docker network");
    } else {
        eprintln!("  [WARN] provider and consumer kind nodes may be on different Docker networks");
        eprintln!("         Cross-cluster routing may require NodePort exposure and host-level access");
    }

    println!();
    Ok(())
}

/// Get the Docker IP of the first kind node in a cluster.
fn get_kind_node_ip(context: &str) -> Result<String, Box<dyn std::error::Error>> {
    let output = Command::new("kubectl")
        .args([
            "--context",
            context,
            "get",
            "nodes",
            "-o",
            "jsonpath={.items[0].status.addresses[?(@.type==\"InternalIP\")].address}",
        ])
        .output()?;
    let ip = String::from_utf8(output.stdout)?.trim().to_owned();
    if ip.is_empty() {
        return Err(format!("could not get node IP for context {context}").into());
    }
    Ok(ip)
}

/// Get the `NodePort` for a service if it is exposed as `NodePort`.
fn get_nodeport(context: &str, service: &str) -> Option<u16> {
    let output = Command::new("kubectl")
        .args([
            "--context",
            context,
            "get",
            "service",
            service,
            "-n",
            NAMESPACE,
            "-o",
            "jsonpath={.spec.ports[0].nodePort}",
        ])
        .output()
        .ok()?;
    let port_str = String::from_utf8(output.stdout).ok()?;
    port_str.trim().parse().ok().filter(|&p: &u16| p > 0)
}

/// Probe a TCP address.
#[expect(
    clippy::disallowed_methods,
    reason = "synchronous networking probe; no async runtime available"
)]
fn probe_tcp(addr: &str) -> bool {
    let deadline = Instant::now() + PROBE_TIMEOUT;
    loop {
        if TcpStream::connect(addr).is_ok() {
            return true;
        }
        if Instant::now() >= deadline {
            return false;
        }
        std::thread::sleep(Duration::from_millis(500));
    }
}

/// Check whether provider and consumer kind nodes share a Docker network.
fn check_docker_network(provider_ctx: &str, consumer_ctx: &str) -> Result<bool, Box<dyn std::error::Error>> {
    let provider_node = get_node_name(provider_ctx)?;
    let consumer_node = get_node_name(consumer_ctx)?;
    let provider_nets = get_docker_networks(&provider_node);
    let consumer_nets = get_docker_networks(&consumer_node);
    Ok(provider_nets.iter().any(|n| consumer_nets.contains(n)))
}

/// Get the first node name in a cluster.
fn get_node_name(context: &str) -> Result<String, Box<dyn std::error::Error>> {
    let output = Command::new("kubectl")
        .args([
            "--context",
            context,
            "get",
            "nodes",
            "-o",
            "jsonpath={.items[0].metadata.name}",
        ])
        .output()?;
    Ok(String::from_utf8(output.stdout)?.trim().to_owned())
}

/// Get Docker network names for a container (kind node).
fn get_docker_networks(container: &str) -> Vec<String> {
    Command::new("docker")
        .args([
            "inspect",
            "--format",
            "{{range $k,$v := .NetworkSettings.Networks}}{{$k}}\n{{end}}",
            container,
        ])
        .output()
        .ok()
        .and_then(|o| String::from_utf8(o.stdout).ok())
        .unwrap_or_default()
        .lines()
        .map(str::to_owned)
        .collect()
}

// ---------------------------------------------------------------------------
// Consumer gateway deployment
// ---------------------------------------------------------------------------

/// Deploy the consumer gateway.
///
/// Resolves the consumer cluster from the environment config, collects
/// provider `NodePort` endpoints, creates the TLS secret from locally
/// generated certificates, applies a `grid_route` `ConfigMap`, and
/// deploys the Praxis AI gateway Deployment and Service.
///
/// When `overlay_config` is `Some(path)`, reads the routing overlay
/// `grid-config.json` at that path. The overlay `local_site` and candidates
/// drive the `grid_route` stanza; the `load_balancer` section is still
/// generated from provider endpoints in the environment config.
///
/// When `overlay_config` is `None`, the static config derived from provider
/// site/model declarations is used (existing behaviour).
///
/// # Errors
///
/// Returns an error if the consumer cluster is not configured, the overlay
/// file is invalid, no provider gateway endpoints are found, or any
/// Kubernetes apply fails.
pub(crate) fn deploy_consumer(
    cfg: &EnvConfig,
    overlay_config: Option<&Path>,
) -> Result<(), Box<dyn std::error::Error>> {
    let consumer_site = cfg
        .consumer_cluster_name()
        .ok_or("no consumer cluster configured in environment config")?;
    let consumer_ctx = kubectl_context(consumer_site);
    eprintln!("  deploying consumer gateway to {consumer_ctx}...");

    let overlay = overlay_config.map(read_overlay_file).transpose()?;

    let provider_endpoints = collect_provider_endpoints(cfg)?;
    if provider_endpoints.is_empty() {
        return Err("no provider gateway endpoints found".into());
    }

    // When an overlay is provided, filter out candidates whose site has no
    // matching local provider.  This handles overlays produced by the Grid
    // operator that may include remote/API-provider candidates (e.g. external
    // API providers) that cannot be routed through the local kind environment.
    // At least one routeable candidate must remain after filtering.
    let filtered_overlay = if let Some(o) = &overlay {
        Some(filter_overlay_for_local_providers(o, &provider_endpoints)?)
    } else {
        None
    };

    create_consumer_tls_secret(&consumer_ctx, consumer_site)?;
    apply_consumer_config(
        &consumer_ctx,
        consumer_site,
        &provider_endpoints,
        filtered_overlay.as_ref().or(overlay.as_ref()),
    )?;
    apply_consumer_deployment(&consumer_ctx)?;
    rollout_restart(&consumer_ctx, "praxis-consumer")?;

    kubectl::wait_for_rollout(&consumer_ctx, "praxis-consumer", consumer_site)?;

    eprintln!("  [PASS] consumer gateway ready in {consumer_ctx}");
    Ok(())
}

/// Read and parse a routing overlay JSON file.
///
/// # Errors
///
/// Returns an error if the file cannot be read or the JSON is invalid.
fn read_overlay_file(path: &Path) -> Result<RoutingOverlay, Box<dyn std::error::Error>> {
    let json =
        std::fs::read_to_string(path).map_err(|e| format!("could not read overlay file {}: {e}", path.display()))?;
    Ok(operator_overlay::parse_grid_config_json(&json)?)
}

/// Filter an operator-generated overlay to only candidates routable locally.
///
/// Retains candidates whose `site` field matches a configured provider site.
/// Candidates referencing remote or external-API sites (e.g. sites only
/// reachable via SWIM discovery or external network) are logged and dropped.
///
/// # Errors
///
/// Returns an error when all candidates are filtered out — no locally-routable
/// route would remain, making the consumer gateway deployment useless.
#[expect(
    clippy::too_many_lines,
    reason = "per-candidate filtering loop with diagnostic output for each excluded candidate"
)]
fn filter_overlay_for_local_providers(
    overlay: &RoutingOverlay,
    providers: &[ProviderEndpoint],
) -> Result<RoutingOverlay, Box<dyn std::error::Error>> {
    let known_sites: Vec<&str> = providers.iter().map(|p| p.site.as_str()).collect();
    let mut kept = Vec::new();
    for c in &overlay.candidates {
        // Accept the candidate when either the `site` field or the `cluster` field matches a
        // known local provider.  The `cluster` field (derived from `routingClusterRef`) is the
        // stable routing identity; `site` may differ when auto-discovered `GridSite` resources
        // are present, causing the overlay renderer to use the `GridSite` name as the site field
        // instead of `routingClusterRef`.
        if known_sites.contains(&c.site.as_str()) || known_sites.contains(&c.cluster.as_str()) {
            kept.push(c.clone());
        } else {
            eprintln!(
                "  [INFO] overlay candidate model=\"{}\" site=\"{}\" cluster=\"{}\" \
                 has no local provider endpoint (known: [{}]); excluded from consumer gateway config",
                c.name,
                c.site,
                c.cluster,
                known_sites.join(", ")
            );
        }
    }
    if kept.is_empty() {
        return Err(format!(
            "no overlay candidates have a matching local provider endpoint; \
             known provider sites: [{}]; \
             hint: set spec.routingClusterRef on InferenceProvider resources \
             to match a local provider site name",
            known_sites.join(", ")
        )
        .into());
    }
    Ok(RoutingOverlay {
        network: overlay.network.clone(),
        local_site: overlay.local_site.clone(),
        candidates: kept,
    })
}

/// Verify that every overlay candidate site has a matching provider endpoint.
///
/// The `load_balancer` section uses `gateway-{provider.site}` as cluster
/// names.  The `grid_route` candidates use `gateway-{candidate.site}`.  For
/// Praxis to route successfully, both sides must reference the same sites.
///
/// This function is used in unit tests to validate individual candidate
/// sets.  Production deployment uses [`filter_overlay_for_local_providers`]
/// instead, which skips un-routable candidates rather than failing.
///
/// # Errors
///
/// Returns an error if any `candidate.site` is absent from the provider list,
/// including the model name, the unknown site, and the known provider sites.
#[cfg(test)]
fn validate_overlay_sites_supported(
    overlay: &RoutingOverlay,
    providers: &[ProviderEndpoint],
) -> Result<(), Box<dyn std::error::Error>> {
    let known_sites: Vec<&str> = providers.iter().map(|p| p.site.as_str()).collect();
    for c in &overlay.candidates {
        if !known_sites.contains(&c.site.as_str()) {
            return Err(format!(
                "overlay candidate model=\"{}\" site=\"{}\" cluster=\"{}\" \
                 has no matching local provider endpoint\n\
                 known provider sites: [{}]\n\
                 hint: set spec.routingClusterRef on the InferenceProvider \
                 to a site name from the environment config",
                c.name,
                c.site,
                c.cluster,
                known_sites.join(", ")
            )
            .into());
        }
    }
    Ok(())
}

/// Collect provider gateway endpoints for consumer routing.
///
/// Tries to get `NodePort` addresses for each provider cluster.
/// If no `NodePort` exists, exposes one.
fn collect_provider_endpoints(cfg: &EnvConfig) -> Result<Vec<ProviderEndpoint>, Box<dyn std::error::Error>> {
    let mut endpoints = Vec::new();
    for name in &cfg.clusters.names {
        let Some(def) = cfg.clusters.definitions.get(name) else {
            continue;
        };
        if def.role != ClusterRole::Provider || def.models.is_empty() {
            continue;
        }
        endpoints.push(resolve_provider_endpoint(name, def)?);
    }
    for ep in &endpoints {
        eprintln!(
            "  provider endpoint: {} @ {} (models: {})",
            ep.site,
            ep.address,
            ep.models.join(", ")
        );
    }
    Ok(endpoints)
}

/// Resolve the reachable endpoint for one provider cluster.
fn resolve_provider_endpoint(name: &str, def: &ClusterDef) -> Result<ProviderEndpoint, Box<dyn std::error::Error>> {
    let ctx = kubectl_context(name);
    let node_port = if let Some(p) = get_nodeport(&ctx, "praxis-provider") {
        p
    } else {
        eprintln!("  [WARN] no NodePort for {name}; exposing via NodePort now...");
        expose_gateway_nodeport(&ctx, name)?;
        get_nodeport(&ctx, "praxis-provider").unwrap_or(NODE_PORT_BASE)
    };
    let node_ip = get_kind_node_ip(&ctx).unwrap_or_else(|_| "127.0.0.1".to_owned());
    Ok(ProviderEndpoint {
        site: name.to_owned(),
        address: format!("{node_ip}:{node_port}"),
        models: def.models.clone(),
        sni: format!("{name}.grid.internal"),
    })
}

/// Expose a provider gateway as `NodePort` if not already exposed.
fn expose_gateway_nodeport(context: &str, site: &str) -> Result<(), Box<dyn std::error::Error>> {
    let status = Command::new("kubectl")
        .args([
            "--context",
            context,
            "-n",
            NAMESPACE,
            "patch",
            "service",
            "praxis-provider",
            "-p",
            &format!(
                r#"{{"spec":{{"type":"NodePort","ports":[{{"port":{GATEWAY_HTTP_PORT},"targetPort":{GATEWAY_HTTP_PORT},"nodePort":{NODE_PORT_BASE}}}]}}}}"#
            ),
        ])
        .status()?;
    if !status.success() {
        return Err(format!("failed to patch praxis-provider service in {site}").into());
    }
    Ok(())
}

/// Provider endpoint resolved for consumer routing.
struct ProviderEndpoint {
    /// Site name (matches the provider cluster name).
    site: String,
    /// Reachable `host:port` address for the provider gateway.
    address: String,
    /// Configured model names for this provider.
    models: Vec<String>,
    /// TLS SNI hostname (used in future mTLS extensions).
    #[expect(dead_code, reason = "future mTLS extension point")]
    sni: String,
}

/// Create (or update) the TLS secret in the consumer cluster.
///
/// Loads the locally-generated certificate for `consumer_site`, its private
/// key, and the local CA certificate from `tests/env/certs/`.  These are
/// created by `xtask env up`.
fn create_consumer_tls_secret(context: &str, consumer_site: &str) -> Result<(), Box<dyn std::error::Error>> {
    let certs_dir = PathBuf::from(HOST_CERTS_DIR);
    let cert = certs_dir.join(format!("{consumer_site}-cert.pem"));
    let key = certs_dir.join(format!("{consumer_site}-key.pem"));
    let ca = certs_dir.join("ca.pem");

    eprintln!("  creating TLS secret in {context}...");

    let output = Command::new("kubectl")
        .args([
            "create",
            "secret",
            "generic",
            TLS_SECRET_NAME,
            &format!("--from-file=tls.crt={}", cert.display()),
            &format!("--from-file=tls.key={}", key.display()),
            &format!("--from-file=ca.crt={}", ca.display()),
            "--namespace",
            NAMESPACE,
            "--dry-run=client",
            "-o",
            "yaml",
        ])
        .output()?;

    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        return Err(format!("kubectl create secret failed: {stderr}").into());
    }

    let yaml = String::from_utf8(output.stdout)?;
    kubectl::apply_manifest(context, &yaml)
}

/// Apply the consumer gateway `ConfigMap`.
///
/// When `overlay` is `Some`, uses overlay candidates and `local_site`.
/// When `overlay` is `None`, uses static config from `consumer_site` and `providers`.
fn apply_consumer_config(
    context: &str,
    consumer_site: &str,
    providers: &[ProviderEndpoint],
    overlay: Option<&RoutingOverlay>,
) -> Result<(), Box<dyn std::error::Error>> {
    let config = consumer_gateway_config(consumer_site, providers, overlay);
    let yaml = format!(
        "apiVersion: v1\n\
         kind: ConfigMap\n\
         metadata:\n\
         \x20 name: praxis-consumer-config\n\
         \x20 namespace: {NAMESPACE}\n\
         data:\n\
         \x20 praxis.yaml: |\n\
         {}\n",
        indent_yaml(&config, 4)
    );
    kubectl::apply_manifest(context, &yaml)
}

/// Build the consumer Praxis config YAML.
///
/// When `overlay` is `Some`, candidates are taken from the overlay;
/// the `load_balancer` section is still generated from `providers` so that
/// mTLS endpoint config is preserved.
///
/// When `overlay` is `None`, generates a static `grid_route` stanza from
/// `providers` (one candidate per model per site).
///
/// `grid_route.local_site` is always `consumer_site` — the consumer's own
/// cluster identity.  The overlay's `local_site` field identifies the
/// `GridNetwork`, not the consumer site, and must not be used here.
///
/// A `load_balancer` section provides mTLS cluster definitions for each
/// provider.  A catch-all `router` route falls through to the first provider
/// cluster for requests without a recognised model header.
///
/// The `grid_route` cluster convention is `gateway-{site}`, which must match
/// the names produced by [`build_clusters`].
#[expect(clippy::too_many_lines, reason = "Praxis config YAML generation")]
fn consumer_gateway_config(
    consumer_site: &str,
    providers: &[ProviderEndpoint],
    overlay: Option<&RoutingOverlay>,
) -> String {
    let candidates = if let Some(o) = overlay {
        operator_overlay::candidates_yaml(o)
    } else {
        build_grid_route_candidates(providers)
    };
    let local_site = consumer_site;
    let clusters = build_clusters(providers);
    format!(
        "listeners:\n\
         \x20 - name: public\n\
         \x20   address: \"0.0.0.0:{GATEWAY_HTTP_PORT}\"\n\
         \x20   filter_chains:\n\
         \x20     - consumer-chain\n\
         filter_chains:\n\
         \x20 - name: consumer-chain\n\
         \x20   filters:\n\
         \x20     - filter: json_body_field\n\
         \x20       field: model\n\
         \x20       header: X-Model\n\
         \x20     - filter: grid_route\n\
         \x20       local_site: {local_site}\n\
         \x20       model_header: X-Model\n\
         \x20       candidates:\n\
         {candidates}\n\
         \x20     - filter: load_balancer\n\
         \x20       clusters:\n\
         {clusters}\n\
         admin:\n\
         \x20 address: \"127.0.0.1:9901\"\n\
         shutdown_timeout_secs: 5\n"
    )
}

/// Build `grid_route` candidate entries from provider endpoints.
///
/// Each `(model, site)` pair becomes one `inference_model` candidate.
/// The cluster name is `gateway-{site}`, matching the `load_balancer` section.
fn build_grid_route_candidates(providers: &[ProviderEndpoint]) -> String {
    providers
        .iter()
        .flat_map(|ep| {
            ep.models.iter().map(move |m| {
                format!(
                    "\x20\x20\x20\x20\x20\x20\x20\x20 - kind: inference_model\n\
                     \x20\x20\x20\x20\x20\x20\x20\x20\x20\x20 name: {m}\n\
                     \x20\x20\x20\x20\x20\x20\x20\x20\x20\x20 site: {}\n\
                     \x20\x20\x20\x20\x20\x20\x20\x20\x20\x20 cluster: gateway-{}",
                    ep.site, ep.site
                )
            })
        })
        .collect::<Vec<_>>()
        .join("\n")
}

/// Build `load_balancer` cluster entries for each provider.
///
/// Each cluster uses mTLS: the consumer presents its locally-generated client
/// certificate, and verifies the provider server certificate against the
/// locally-generated CA.  SNI is set to `{site}.grid.internal` which must
/// match the Subject Alternative Name in the provider's server certificate.
fn build_clusters(providers: &[ProviderEndpoint]) -> String {
    providers
        .iter()
        .map(|ep| {
            [
                format!("         - name: gateway-{}", ep.site),
                "           tls:".to_owned(),
                "             ca:".to_owned(),
                format!("               ca_path: {CERT_MOUNT_PATH}/ca.crt"),
                "             client_cert:".to_owned(),
                format!("               cert_path: {CERT_MOUNT_PATH}/tls.crt"),
                format!("               key_path: {CERT_MOUNT_PATH}/tls.key"),
                format!("             sni: {}.grid.internal", ep.site),
                "             verify: true".to_owned(),
                "           endpoints:".to_owned(),
                format!("             - \"{}\"", ep.address),
            ]
            .join("\n")
        })
        .collect::<Vec<_>>()
        .join("\n")
}

/// Apply the consumer gateway Deployment and Service.
#[expect(clippy::too_many_lines, reason = "K8s manifest generation")]
fn apply_consumer_deployment(context: &str) -> Result<(), Box<dyn std::error::Error>> {
    let yaml = format!(
        "apiVersion: apps/v1\n\
         kind: Deployment\n\
         metadata:\n\
         \x20 name: praxis-consumer\n\
         \x20 namespace: {NAMESPACE}\n\
         spec:\n\
         \x20 replicas: 1\n\
         \x20 selector:\n\
         \x20   matchLabels:\n\
         \x20     app: praxis-consumer\n\
         \x20 template:\n\
         \x20   metadata:\n\
         \x20     labels:\n\
         \x20       app: praxis-consumer\n\
         \x20   spec:\n\
         \x20     containers:\n\
         \x20       - name: praxis-ai\n\
         \x20         image: {GATEWAY_IMAGE}\n\
         \x20         imagePullPolicy: Never\n\
         \x20         ports:\n\
         \x20           - containerPort: {GATEWAY_HTTP_PORT}\n\
         \x20         args:\n\
         \x20           - \"--config\"\n\
         \x20           - \"/etc/praxis/praxis.yaml\"\n\
         \x20         volumeMounts:\n\
         \x20           - name: config\n\
         \x20             mountPath: /etc/praxis\n\
         \x20             readOnly: true\n\
         \x20           - name: tls-certs\n\
         \x20             mountPath: {CERT_MOUNT_PATH}\n\
         \x20             readOnly: true\n\
         \x20     volumes:\n\
         \x20       - name: config\n\
         \x20         configMap:\n\
         \x20           name: praxis-consumer-config\n\
         \x20       - name: tls-certs\n\
         \x20         secret:\n\
         \x20           secretName: {TLS_SECRET_NAME}\n\
         ---\n\
         apiVersion: v1\n\
         kind: Service\n\
         metadata:\n\
         \x20 name: praxis-consumer\n\
         \x20 namespace: {NAMESPACE}\n\
         spec:\n\
         \x20 selector:\n\
         \x20   app: praxis-consumer\n\
         \x20 ports:\n\
         \x20   - port: {GATEWAY_HTTP_PORT}\n\
         \x20     targetPort: {GATEWAY_HTTP_PORT}\n"
    );
    kubectl::apply_manifest(context, &yaml)
}

/// Deploy the consumer gateway with an additional Secret volume mount.
///
/// Extends [`apply_consumer_deployment`] with a `volumes` / `volumeMounts`
/// entry that makes the credential Secret available at
/// `{CREDENTIAL_MOUNT_BASE}/{secret_name}/{secret_key}` inside the pod.
///
/// This allows `grid_credential_inject` to use `file:` as its token source
/// rather than an inline `value:`, keeping token bytes out of `ConfigMap`s.
#[expect(
    clippy::too_many_lines,
    reason = "Deployment + Service YAML with two volumes; mirrors apply_consumer_deployment"
)]
fn apply_consumer_deployment_with_credential_mount(
    context: &str,
    secret_name: &str,
    secret_key: &str,
) -> Result<(), Box<dyn std::error::Error>> {
    let mount_path = format!("{CREDENTIAL_MOUNT_BASE}/{secret_name}");
    let yaml = format!(
        "apiVersion: apps/v1\n\
         kind: Deployment\n\
         metadata:\n\
         \x20 name: praxis-consumer\n\
         \x20 namespace: {NAMESPACE}\n\
         spec:\n\
         \x20 replicas: 1\n\
         \x20 selector:\n\
         \x20   matchLabels:\n\
         \x20     app: praxis-consumer\n\
         \x20 template:\n\
         \x20   metadata:\n\
         \x20     labels:\n\
         \x20       app: praxis-consumer\n\
         \x20   spec:\n\
         \x20     containers:\n\
         \x20       - name: praxis-ai\n\
         \x20         image: {GATEWAY_IMAGE}\n\
         \x20         imagePullPolicy: Never\n\
         \x20         ports:\n\
         \x20           - containerPort: {GATEWAY_HTTP_PORT}\n\
         \x20         args:\n\
         \x20           - \"--config\"\n\
         \x20           - \"/etc/praxis/praxis.yaml\"\n\
         \x20         volumeMounts:\n\
         \x20           - name: config\n\
         \x20             mountPath: /etc/praxis\n\
         \x20             readOnly: true\n\
         \x20           - name: tls-certs\n\
         \x20             mountPath: {CERT_MOUNT_PATH}\n\
         \x20             readOnly: true\n\
         \x20           - name: api-creds\n\
         \x20             mountPath: {mount_path}\n\
         \x20             readOnly: true\n\
         \x20     volumes:\n\
         \x20       - name: config\n\
         \x20         configMap:\n\
         \x20           name: praxis-consumer-config\n\
         \x20       - name: tls-certs\n\
         \x20         secret:\n\
         \x20           secretName: {TLS_SECRET_NAME}\n\
         \x20       - name: api-creds\n\
         \x20         secret:\n\
         \x20           secretName: {secret_name}\n\
         \x20           items:\n\
         \x20             - key: {secret_key}\n\
         \x20               path: {secret_key}\n\
         ---\n\
         apiVersion: v1\n\
         kind: Service\n\
         metadata:\n\
         \x20 name: praxis-consumer\n\
         \x20 namespace: {NAMESPACE}\n\
         spec:\n\
         \x20 selector:\n\
         \x20   app: praxis-consumer\n\
         \x20 ports:\n\
         \x20   - port: {GATEWAY_HTTP_PORT}\n\
         \x20     targetPort: {GATEWAY_HTTP_PORT}\n"
    );
    kubectl::apply_manifest(context, &yaml)
}

// ---------------------------------------------------------------------------
// API provider fallback consumer deployment
// ---------------------------------------------------------------------------

/// Build the Praxis consumer config for the API-provider fallback validation.
///
/// Generates a `grid_route` section from the overlay (which must include both
/// the local provider and the `api_provider` candidate), and a `load_balancer`
/// section with:
///
/// - mTLS clusters for each local provider (identical to the standard path).
/// - A **plain-HTTP** cluster for `gateway-{api_cluster}` pointing to the in-cluster mock API-provider service.  No TLS
///   is used for this cluster because the mock represents a direct API endpoint, not a Grid provider gateway.  In
///   production the gateway would reach the provider over HTTPS using credentials managed by the operator; the kind
///   mock uses HTTP for simplicity.
///
/// The caller passes the raw overlay (all candidates intact — no
/// `filter_overlay_for_local_providers` is applied) so that the API-provider
/// candidate survives into the `grid_route` stanza.
///
/// Credential injection here is gateway-config-level proof using Praxis
/// `headers` / `request_set`. It does not prove the future operator path that
/// reads an `InferenceProvider` Secret reference and manages credential rotation.
///
/// **Caveat:** the bearer token is necessarily present in the generated Praxis
/// consumer `ConfigMap` (`praxis-consumer-config`).  For the xtask validation
/// harness this is acceptable; production deployments should use mounted Secret
/// volumes or a native Praxis secret-reference mechanism.
#[expect(
    clippy::too_many_lines,
    reason = "Praxis YAML generation with mTLS and plain-HTTP clusters"
)]
#[expect(
    clippy::too_many_arguments,
    reason = "six distinct config parameters: site, providers, overlay, cluster name, endpoint, token"
)]
fn build_api_fallback_consumer_config(
    consumer_site: &str,
    local_providers: &[ProviderEndpoint],
    overlay: &RoutingOverlay,
    api_cluster_name: &str,
    api_provider_endpoint: &str,
    api_provider_token: &str,
) -> String {
    let candidates = operator_overlay::candidates_yaml(overlay);
    let local_site = consumer_site;
    let mtls_clusters = build_clusters(local_providers);
    let api_cluster_yaml = format!(
        r#"         - name: gateway-{api_cluster_name}
           endpoints:
             - "{api_provider_endpoint}""#
    );

    format!(
        r#"listeners:
  - name: public
    address: "0.0.0.0:{GATEWAY_HTTP_PORT}"
    filter_chains:
      - consumer-chain
filter_chains:
  - name: consumer-chain
    filters:
      - filter: json_body_field
        field: model
        header: X-Model
      - filter: grid_route
        local_site: {local_site}
        model_header: X-Model
        candidates:
{candidates}
      - filter: headers
        request_set:
          - name: "Authorization"
            value: "Bearer {api_provider_token}"
      - filter: load_balancer
        clusters:
{mtls_clusters}
{api_cluster_yaml}
admin:
  address: "127.0.0.1:9901"
shutdown_timeout_secs: 5
"#
    )
}

/// Build the consumer Praxis config for API-provider fallback routing — native injection mode.
///
/// Unlike [`build_api_fallback_consumer_config`] which embeds the bearer token as a
/// static string inside `filter: headers` / `request_set`, this native variant:
///
/// - Emits credential `secretRef` data in the `grid_route` candidates block via
///   [`operator_overlay::candidates_yaml_with_credentials`].
/// - Uses `filter: grid_credential_inject` with a `file:` source pointing at the mounted Kubernetes Secret file — token
///   bytes never appear in the `ConfigMap`.
///
/// **Token placement:** the bearer token is read by `grid_credential_inject` from
/// the file at `{CREDENTIAL_MOUNT_BASE}/{secret_name}/{secret_key}` inside the pod.
/// **The token does not appear in this `ConfigMap`**, in the operator overlay JSON,
/// or in the `grid_route` candidates block.
#[expect(
    clippy::too_many_lines,
    reason = "Praxis YAML generation with mTLS + plain-HTTP clusters and native credential inject"
)]
#[expect(
    clippy::too_many_arguments,
    reason = "distinct argument per secretRef field — collapsing would obscure the security boundary"
)]
fn build_api_fallback_consumer_config_native(
    consumer_site: &str,
    local_providers: &[ProviderEndpoint],
    overlay: &RoutingOverlay,
    api_cluster_name: &str,
    api_provider_endpoint: &str,
    secret_name: &str,
    secret_namespace: &str,
    secret_key: &str,
) -> String {
    let candidates = operator_overlay::candidates_yaml_with_credentials(overlay);
    let local_site = consumer_site;
    let mtls_clusters = build_clusters(local_providers);
    let api_cluster_yaml = format!(
        r#"         - name: gateway-{api_cluster_name}
           endpoints:
             - "{api_provider_endpoint}""#
    );
    // Token read from mounted file — never embedded in this YAML.
    let token_file_path = format!("{CREDENTIAL_MOUNT_BASE}/{secret_name}/{secret_key}");

    format!(
        r#"listeners:
  - name: public
    address: "0.0.0.0:{GATEWAY_HTTP_PORT}"
    filter_chains:
      - consumer-chain
filter_chains:
  - name: consumer-chain
    filters:
      - filter: json_body_field
        field: model
        header: X-Model
      - filter: grid_route
        local_site: {local_site}
        model_header: X-Model
        candidates:
{candidates}
      - filter: grid_credential_inject
        credentials:
          - name: {secret_name}
            namespace: {secret_namespace}
            key: {secret_key}
            strategy: bearer_token
            file: {token_file_path}
      - filter: load_balancer
        clusters:
{mtls_clusters}
{api_cluster_yaml}
admin:
  address: "127.0.0.1:9901"
shutdown_timeout_secs: 5
"#
    )
}

/// Deploy the consumer gateway configured for API-provider fallback — native injection mode.
///
/// Uses [`build_api_fallback_consumer_config_native`] which emits credential secretRef
/// in the `grid_route` candidates block and uses `filter: grid_credential_inject`
/// with a `file:` source.
///
/// **Token placement:** the bearer token is read from a mounted Kubernetes Secret
/// file at `{CREDENTIAL_MOUNT_BASE}/{secret_name}/{secret_key}` inside the pod.
/// The token does **not** appear in the consumer Praxis `ConfigMap`, in the
/// operator overlay JSON, or in the `grid_route` candidates block.
#[expect(
    clippy::too_many_lines,
    reason = "sequential deploy steps: tls secret, config, deployment with credential mount, rollout"
)]
#[expect(
    clippy::too_many_arguments,
    reason = "distinct argument per secretRef field — collapsing would obscure the security boundary"
)]
pub(crate) fn deploy_consumer_for_api_fallback_native(
    cfg: &EnvConfig,
    overlay: &RoutingOverlay,
    api_cluster_name: &str,
    api_provider_endpoint: &str,
    secret_name: &str,
    secret_namespace: &str,
    secret_key: &str,
) -> Result<(), Box<dyn std::error::Error>> {
    let consumer_site = cfg
        .consumer_cluster_name()
        .ok_or("no consumer cluster configured in environment config")?;
    let consumer_ctx = kubectl_context(consumer_site);
    eprintln!("  deploying native-credential consumer gateway to {consumer_ctx}...");

    let provider_endpoints = collect_provider_endpoints(cfg)?;
    if provider_endpoints.is_empty() {
        return Err("no provider gateway endpoints found in config".into());
    }

    let config = build_api_fallback_consumer_config_native(
        consumer_site,
        &provider_endpoints,
        overlay,
        api_cluster_name,
        api_provider_endpoint,
        secret_name,
        secret_namespace,
        secret_key,
    );

    create_consumer_tls_secret(&consumer_ctx, consumer_site)?;

    let yaml = format!(
        "apiVersion: v1\n\
         kind: ConfigMap\n\
         metadata:\n\
         \x20 name: praxis-consumer-config\n\
         \x20 namespace: {NAMESPACE}\n\
         data:\n\
         \x20 praxis.yaml: |\n\
         {}\n",
        indent_yaml(&config, 4)
    );
    kubectl::apply_manifest(&consumer_ctx, &yaml)?;

    // Mount the credential Secret as a file — the token never touches the ConfigMap.
    apply_consumer_deployment_with_credential_mount(&consumer_ctx, secret_name, secret_key)?;
    rollout_restart(&consumer_ctx, "praxis-consumer")?;
    kubectl::wait_for_rollout(&consumer_ctx, "praxis-consumer", consumer_site)?;

    eprintln!("  [PASS] native-credential consumer gateway ready in {consumer_ctx}");
    Ok(())
}

