/// Verify consumer-to-provider gateway routing end-to-end.
///
/// Port-forwards to the consumer gateway, then for each configured provider
/// model sends a Chat Completions request and asserts a 200 response with
/// valid JSON.  Also asserts that an unknown model fails cleanly (404 or 503).
///
/// # Errors
///
/// Returns an error if any assertion fails.
#[expect(clippy::too_many_lines, reason = "multi-cluster E2E verification loop")]
pub(crate) fn verify_e2e(cfg: &EnvConfig) -> Result<(), Box<dyn std::error::Error>> {
    let consumer_site = cfg
        .consumer_cluster_name()
        .ok_or("no consumer cluster configured in environment config")?;
    let mut tally = Tally::default();
    let ctx = kubectl_context(consumer_site);

    let port = find_free_port()?;
    let mut pf = PortForwardGuard::start(&ctx, "praxis-consumer", port, GATEWAY_HTTP_PORT)?;

    if !wait_for_port(port) {
        tally.fail(consumer_site, "consumer gateway reachable via port-forward", &ctx);
        pf.stop();
        return tally.print_summary();
    }
    tally.pass(consumer_site, "consumer gateway reachable via port-forward");

    for name in &cfg.clusters.names {
        let Some(def) = cfg.clusters.definitions.get(name) else {
            continue;
        };
        if def.role != ClusterRole::Provider {
            continue;
        }
        for model in &def.models {
            verify_consumer_model(&ctx, port, name, model, consumer_site, &mut tally);
        }
    }

    match send_consumer_request(port, "nonexistent-model-xyz") {
        Ok(resp) if resp.status == 404 || resp.status == 503 => {
            tally.pass(consumer_site, "unknown model fails cleanly via consumer gateway");
        },
        Ok(resp) => {
            tally.fail(
                consumer_site,
                &format!("unknown model returned {} (expected 404 or 503)", resp.status),
                &ctx,
            );
        },
        Err(e) => {
            tally.fail(consumer_site, &format!("unknown model request failed: {e}"), &ctx);
        },
    }

    pf.stop();
    tally.print_summary()
}

/// Verify a single model routes correctly from the consumer to a provider.
#[expect(clippy::too_many_lines, reason = "per-model assertion chain")]
#[expect(
    clippy::too_many_arguments,
    reason = "all args are distinct non-groupable identifiers"
)]
fn verify_consumer_model(
    context: &str,
    port: u16,
    provider: &str,
    model: &str,
    consumer_site: &str,
    tally: &mut Tally,
) {
    match send_consumer_request(port, model) {
        Ok(resp) if resp.status == 200 => {
            tally.pass(
                consumer_site,
                &format!("model {model} (from {provider}) returns 200 via consumer gateway"),
            );
            if let Ok(json) = serde_json::from_str::<serde_json::Value>(&resp.body) {
                if json.get("choices").is_some_and(serde_json::Value::is_array) {
                    tally.pass(
                        consumer_site,
                        &format!("model {model} response is valid Chat Completions JSON"),
                    );
                } else {
                    let excerpt = safe_truncate(&resp.body, 200);
                    tally.fail(
                        consumer_site,
                        &format!("model {model} response missing choices\n         body: {excerpt}"),
                        context,
                    );
                }
            }
        },
        Ok(resp) => {
            let excerpt = safe_truncate(&resp.body, 200);
            tally.fail(
                consumer_site,
                &format!(
                    "model {model} returned {} (expected 200)\n         body: {excerpt}",
                    resp.status
                ),
                context,
            );
        },
        Err(e) => {
            tally.fail(
                consumer_site,
                &format!("model {model} request via consumer failed: {e}"),
                context,
            );
        },
    }
}

/// Send a Chat Completions request to the consumer gateway.
///
/// The `Authorization: Bearer` header is required by the `mock-openai` provider backend.
pub(crate) fn send_consumer_request(port: u16, model: &str) -> Result<HttpResponse, Box<dyn std::error::Error>> {
    let url = format!("http://127.0.0.1:{port}/v1/chat/completions");
    let body = format!(r#"{{"model":"{model}","messages":[{{"role":"user","content":"hello"}}],"max_tokens":1}}"#);
    let output = Command::new("curl")
        .args([
            "-s",
            "-w",
            "\n%{http_code}",
            "--connect-timeout",
            "5",
            "--max-time",
            "15",
            "-X",
            "POST",
            "-H",
            "Authorization: Bearer dummy-key",
            "-H",
            "Content-Type: application/json",
            "-d",
            &body,
            &url,
        ])
        .output()?;
    parse_curl_output(&String::from_utf8(output.stdout)?)
}

/// Send a Chat Completions request without any `Authorization` header.
///
/// Used in the credential-injection proof to show that when the client does
/// not provide an `Authorization: Bearer` header, a request that goes
/// **directly** to the mock API-provider returns `401 Unauthorized`, while a
/// request that goes **through the consumer gateway** (which uses
/// `filter: headers` / `request_set` to inject
/// `Authorization: Bearer grid-api-fallback-secret`) returns `200 OK`.
fn send_request_without_auth(port: u16, model: &str) -> Result<HttpResponse, Box<dyn std::error::Error>> {
    let url = format!("http://127.0.0.1:{port}/v1/chat/completions");
    let body = format!(r#"{{"model":"{model}","messages":[{{"role":"user","content":"hello"}}],"max_tokens":1}}"#);
    let output = Command::new("curl")
        .args([
            "-s",
            "-w",
            "\n%{http_code}",
            "--connect-timeout",
            "5",
            "--max-time",
            "15",
            "-X",
            "POST",
            "-H",
            "Content-Type: application/json",
            "-d",
            &body,
            &url,
        ])
        .output()?;
    parse_curl_output(&String::from_utf8(output.stdout)?)
}

/// Verify gateway-level credential injection for the API-provider fallback.
///
/// Proves that:
/// 1. The mock API-provider rejects requests with no `Authorization` header (status 401). This establishes that the
///    credential is genuinely required by the backend.
/// 2. A request routed through the consumer gateway — which injects `Authorization: Bearer grid-api-fallback-secret`
///    via `filter: headers / request_set` — succeeds with status 200. The client request carries **no** `Authorization`
///    header; only the gateway config knows the provider credential.
///
/// Together these two assertions prove transparent provider credential injection:
/// the client is unaware of the provider API key; the grid infrastructure manages it.
#[expect(
    clippy::too_many_lines,
    reason = "two-phase credential injection proof: negative then positive"
)]
#[expect(
    clippy::too_many_arguments,
    reason = "six distinct parameters: context, two ports, model, secret name, tally"
)]
pub(crate) fn verify_credential_injection(
    context: &str,
    consumer_port: u16,
    api_model: &str,
    mock_api_port: u16,
    api_provider_secret: &str,
    tally: &mut Tally,
) {
    let consumer_site = "consumer";

    // ── Negative proof: direct mock request without auth returns 401 ──────────
    match send_request_without_auth(mock_api_port, api_model) {
        Ok(resp) if resp.status == 401 => {
            tally.pass(
                consumer_site,
                "credential injection negative proof: direct request to mock api-provider \
                 without Authorization returns 401 (mock requires credential)",
            );
        },
        Ok(resp) => {
            tally.fail(
                consumer_site,
                &format!(
                    "credential injection negative proof failed: direct mock request returned {} \
                     (expected 401 — mock should reject unauthenticated requests)",
                    resp.status
                ),
                context,
            );
        },
        Err(e) => {
            tally.fail(
                consumer_site,
                &format!("credential injection negative proof failed: direct mock request error: {e}"),
                context,
            );
        },
    }

    // ── Positive proof: consumer gateway injects credential → 200 ──────────────
    match send_request_without_auth(consumer_port, api_model) {
        Ok(resp) if resp.status == 200 => {
            tally.pass(
                consumer_site,
                &format!(
                    "credential injection positive proof: consumer gateway request for \
                     {api_model:?} without client Authorization returns 200 \
                     (gateway injected bearer token from Secret {api_provider_secret:?})"
                ),
            );
            if serde_json::from_str::<serde_json::Value>(&resp.body)
                .ok()
                .and_then(|j| {
                    j.get("choices")
                        .and_then(serde_json::Value::as_array)
                        .map(|a| !a.is_empty())
                })
                .unwrap_or(false)
            {
                tally.pass(
                    consumer_site,
                    "injected credential: api-provider response is valid Chat Completions JSON",
                );
            }
        },
        Ok(resp) => {
            let excerpt = safe_truncate(&resp.body, 200);
            tally.fail(
                consumer_site,
                &format!(
                    "credential injection positive proof failed: consumer gateway returned {} \
                     (expected 200 — filter: headers / request_set may not be supported by \
                     this Praxis build, or the config was not applied correctly)\n\
                     body: {excerpt}",
                    resp.status
                ),
                context,
            );
        },
        Err(e) => {
            tally.fail(
                consumer_site,
                &format!("credential injection positive proof failed: consumer gateway error: {e}"),
                context,
            );
        },
    }
}

// ---------------------------------------------------------------------------
// Shared helpers
// ---------------------------------------------------------------------------

/// Build the `kubectl rollout restart` argument list.
///
/// Separated from [`rollout_restart`] so tests can verify the argument
/// structure without spawning a process.
fn rollout_restart_args(context: &str, deployment: &str) -> Vec<String> {
    vec![
        "--context".to_owned(),
        context.to_owned(),
        "-n".to_owned(),
        NAMESPACE.to_owned(),
        "rollout".to_owned(),
        "restart".to_owned(),
        format!("deployment/{deployment}"),
    ]
}

/// Trigger a `rollout restart` so the `Deployment` picks up `ConfigMap` changes.
///
/// `kubectl apply` updates a `ConfigMap` but does not restart the pod.  Calling
/// this after applying the consumer config ensures the pod reloads with the
/// new configuration before [`kubectl::wait_for_rollout`] declares it ready.
///
/// **xtask validation concern only.**  In production, Praxis detects
/// `ConfigMap` mount changes via a file-watch and reloads without a pod
/// restart.  The forced restart here is needed only because the file-watch
/// propagation window is indeterminate during xtask E2E validation — without
/// it, the verify step can race against a Praxis reload that hasn't finished.
fn rollout_restart(context: &str, deployment: &str) -> Result<(), Box<dyn std::error::Error>> {
    let status = Command::new("kubectl")
        .args(rollout_restart_args(context, deployment))
        .status()?;
    if !status.success() {
        return Err(format!("kubectl rollout restart {deployment} failed: {status}").into());
    }
    Ok(())
}

/// Indent each line of a YAML string by `spaces` spaces.
fn indent_yaml(yaml: &str, spaces: usize) -> String {
    let prefix = " ".repeat(spaces);
    yaml.lines()
        .map(|l| {
            if l.is_empty() {
                String::new()
            } else {
                format!("{prefix}{l}")
            }
        })
        .collect::<Vec<_>>()
        .join("\n")
}

